content:
## 行动者

- id: {{ actor.id }}
- 姓名: {{ actor.name }}
- 描述: {{ actor.description }}
- 公开状态: {{ actor.public_state }}
- 私密状态: {{ actor.private_state }}
- 当前活动: {{ actor.current_activity.name }}

## 用户输入

{{ user_input }}

## 世界时间

{{ world_time }}

## 地点

- id: {{ location.id }}
- 名称: {{ location.name }}
- 描述: {{ location.description }}

## 行动者持有的物品堆叠

{% for entry in inventory %}
- stack id: {{ entry.stack_id }}; item id: {{ entry.item_id }}; {{ entry.name }} x{{ entry.quantity }}{% if entry.quality %}; 品质: {{ entry.quality }}{% endif %}; 描述: {{ entry.description }}
{% else %}
- 无
{% endfor %}

## 行动者持有或穿戴的装备

{% for entry in equipment %}
- id: {{ entry.id }}; {{ entry.name }}; 已装备: {{ entry.equipped }}{% if entry.equipped_position %}; 部位: {{ entry.equipped_position }}{% endif %}; 描述: {{ entry.description }}{% if entry.quality %}; 品质: {{ entry.quality }}{% endif %}
{% else %}
- 无
{% endfor %}

## 意图

{% for entry in intents %}
- id: {{ entry.intent.id }}; 名称: {{ entry.intent.name }}; type: {{ entry.intent.type }}; status: {{ entry.intent.status }}; horizon: {{ entry.intent.horizon }}; priority: {{ entry.intent.priority }}; urgency: {{ entry.intent.urgency }}{% if entry.intent.deadline %}; deadline: {{ entry.intent.deadline }}{% endif %}; recall sources: {{ entry.recall_sources }}{% if entry.similarity is not none %}; similarity: {{ entry.similarity }}{% endif %}
  描述: {{ entry.intent.description }}
{% if entry.intent.desired_state %}  期望状态: {{ entry.intent.desired_state }}
{% endif %}  成功条件: {{ entry.intent.success_conditions }}
  失败条件: {{ entry.intent.failure_conditions }}
  维持条件: {{ entry.intent.maintenance_conditions }}
  约束: {{ entry.intent.constraints }}
  当前计划: {{ entry.intent.current_plan }}
  下一步倾向: {{ entry.intent.next_action_biases }}
  阻碍: {{ entry.intent.blockers }}
  未结线索: {{ entry.intent.open_threads }}
{% else %}
- 无
{% endfor %}

## 感知到的角色

{% for entry in perceived_characters %}
- id: {{ entry.character.id }}; 姓名: {{ entry.character.name }}; visibility: {{ entry.visibility }}; salience: {{ entry.salience }}{% if entry.distance_hint %}; 距离: {{ entry.distance_hint }}{% endif %}; 状态: {{ entry.character.public_state }}; affordances: {{ entry.affordances }}{% if entry.notes %}; 备注: {{ entry.notes }}{% endif %}
  可见装备:
{% for equipment in entry.visible_equipment %}
  - id: {{ equipment.id }}; {{ equipment.name }}{% if equipment.equipped_position %}; 部位: {{ equipment.equipped_position }}{% endif %}; 描述: {{ equipment.description }}
{% else %}
  - 无可见装备
{% endfor %}
{% else %}
- 无
{% endfor %}

## 感知到的背景角色

{% for entry in perceived_background_characters %}
- id: {{ entry.character.id }}; 姓名: {{ entry.character.name }}; visibility: {{ entry.visibility }}; salience: {{ entry.salience }}{% if entry.distance_hint %}; 距离: {{ entry.distance_hint }}{% endif %}; 描述: {{ entry.character.description }}; affordances: {{ entry.affordances }}{% if entry.notes %}; 备注: {{ entry.notes }}{% endif %}
{% else %}
- 无
{% endfor %}

## 感知到的地点内物品堆叠

{% for entry in perceived_items %}
- stack id: {{ entry.stack.id }}; item id: {{ entry.item.id }}; {{ entry.item.name }} x{{ entry.stack.quantity }}; visibility: {{ entry.visibility }}; salience: {{ entry.salience }}{% if entry.distance_hint %}; 距离: {{ entry.distance_hint }}{% endif %}; 属于行动者: {{ entry.owned_by_actor }}; affordances: {{ entry.affordances }}{% if entry.notes %}; 备注: {{ entry.notes }}{% endif %}
{% else %}
- 无
{% endfor %}

## 感知到的地点内装备

{% for entry in perceived_equipment %}
- id: {{ entry.equipment.id }}; {{ entry.equipment.name }}; visibility: {{ entry.visibility }}; salience: {{ entry.salience }}{% if entry.distance_hint %}; 距离: {{ entry.distance_hint }}{% endif %}; 属于行动者: {{ entry.owned_by_actor }}; affordances: {{ entry.affordances }}{% if entry.notes %}; 备注: {{ entry.notes }}{% endif %}
{% else %}
- 无
{% endfor %}

## 感知到的地点内容器

{% for entry in perceived_containers %}
- id: {{ entry.container.id }}; {{ entry.container.name }}; state: {{ entry.container.state }}; visibility: {{ entry.visibility }}; salience: {{ entry.salience }}{% if entry.distance_hint %}; 距离: {{ entry.distance_hint }}{% endif %}; 属于行动者: {{ entry.owned_by_actor }}; affordances: {{ entry.affordances }}{% if entry.notes %}; 备注: {{ entry.notes }}{% endif %}
{% else %}
- 无
{% endfor %}

## 感知到的地标

{% for entry in perceived_landmarks %}
- id: {{ entry.landmark.id }}; {{ entry.landmark.name }}; visibility: {{ entry.visibility }}; salience: {{ entry.salience }}{% if entry.distance_hint %}; 距离: {{ entry.distance_hint }}{% endif %}; affordances: {{ entry.affordances }}{% if entry.notes %}; 备注: {{ entry.notes }}{% endif %}
{% else %}
- 无
{% endfor %}

## 召回的记忆

{% for entry in relevant_memories %}
- memory id: {{ entry.memory.id }}; 摘要: {{ entry.memory.summary }}; event: {{ entry.event_name }}; support: {{ entry.support_type }}; confidence: {{ entry.confidence }}; decayed confidence: {{ entry.decayed_confidence }}; salience: {{ entry.salience }}; stance: {{ entry.stance }}; recall sources: {{ entry.recall_sources }}{% if entry.similarity is not none %}; similarity: {{ entry.similarity }}{% endif %}{% if entry.behavioural_relevance %}; 行为相关性: {{ entry.behavioural_relevance }}{% endif %}
{% else %}
- 无
{% endfor %}

## 近期事件

{% for event in recent_events %}
- {{ event }}
{% else %}
- 无
{% endfor %}

## 硬约束

{% for constraint in hard_constraints %}
- {{ constraint }}
{% else %}
- 无
{% endfor %}

## 软约束

{% for constraint in soft_constraints %}
- {{ constraint }}
{% else %}
- 无
{% endfor %}
